import { useConfig } from '@/hooks/useConfig'
import { http } from '@/http/http'

/**
 * ${functionName} API
 */

/**
 * 获取${functionName}表单
 * @param params - 查询参数
 */
export function ${className}Form(params?: Record<string, any>) {
  const config = useConfig()
  return http.post<any>(`\${config.adminPath}/${urlPrefix}/form`, params)
}

/**
 * 获取${functionName}列表
 * @param params - 查询参数
 */
export function ${className}ListData(params?: Record<string, any>) {
  const config = useConfig()
  return http.post<any>(`\${config.adminPath}/${urlPrefix}/listData`, params)
}

/**
 * 保存${functionName}（JSON格式）
 * @param params - 表单数据
 */
export function ${className}Save(params: Record<string, any>, data: Record<string, any>) {
  const config = useConfig()
  return http.postJson<any>(`\${config.adminPath}/${urlPrefix}/save`, params, data)
}
<% if(toBoolean(table.optionMap['isHaveDisableEnable'])){ %>

/**
 * 禁用${functionName}
 * @param params - 表单数据
 */
export function ${className}Disable(params: Record<string, any>) {
  const config = useConfig()
  return http.post<any>(`\${config.adminPath}/${urlPrefix}/disable`, params)
}

/**
 * 启用${functionName}
 * @param params - 表单数据
 */
export function ${className}Enable(params: Record<string, any>) {
  const config = useConfig()
  return http.post<any>(`\${config.adminPath}/${urlPrefix}/enable`, params)
}
<% } %>

/**
 * 删除${functionName}
 * @param params - 表单数据
 */
export function ${className}Delete(params: Record<string, any>) {
  const config = useConfig()
  return http.post<any>(`\${config.adminPath}/${urlPrefix}/delete`, params)
}
<% %>
